// ----- auth.js -----
// PBKDF2 password hashing + HS256 JWT — all via Web Crypto, zero deps.

const PBKDF2_ITERATIONS = 100_000;
const HASH_ALGO = "SHA-256";
const HASH_FORMAT = "pbkdf2_sha256";
const JWT_TTL_SECONDS = 8 * 3600;

function b64UrlEncode(buf) {
  const bytes = buf instanceof Uint8Array ? buf : new Uint8Array(buf);
  let bin = "";
  for (let i = 0; i < bytes.length; i++) bin += String.fromCharCode(bytes[i]);
  return btoa(bin).replace(/\+/g, "-").replace(/\//g, "_").replace(/=+$/, "");
}

function b64UrlDecode(s) {
  const pad = "=".repeat((4 - (s.length % 4)) % 4);
  const bin = atob(s.replace(/-/g, "+").replace(/_/g, "/") + pad);
  const out = new Uint8Array(bin.length);
  for (let i = 0; i < bin.length; i++) out[i] = bin.charCodeAt(i);
  return out;
}

async function pbkdf2(password, saltBytes, iterations) {
  const key = await crypto.subtle.importKey(
    "raw",
    new TextEncoder().encode(password),
    "PBKDF2",
    false,
    ["deriveBits"],
  );
  return crypto.subtle.deriveBits(
    { name: "PBKDF2", salt: saltBytes, iterations, hash: HASH_ALGO },
    key,
    256,
  );
}

/** Hash a plaintext password (use offline, e.g. via scripts/hash_password.py). */
async function hashPassword(plain) {
  const salt = crypto.getRandomValues(new Uint8Array(16));
  const hash = await pbkdf2(plain, salt, PBKDF2_ITERATIONS);
  return `${HASH_FORMAT}$${PBKDF2_ITERATIONS}$${b64UrlEncode(salt)}$${b64UrlEncode(hash)}`;
}

async function verifyPassword(plain, hashed) {
  if (!plain || !hashed) return false;
  const parts = hashed.split("$");
  if (parts.length !== 4 || parts[0] !== HASH_FORMAT) return false;
  const iters = parseInt(parts[1], 10);
  if (!Number.isFinite(iters) || iters < 1000) return false;
  const salt = b64UrlDecode(parts[2]);
  const expected = b64UrlDecode(parts[3]);
  const actual = new Uint8Array(await pbkdf2(plain, salt, iters));
  if (actual.length !== expected.length) return false;
  let diff = 0;
  for (let i = 0; i < actual.length; i++) diff |= actual[i] ^ expected[i];
  return diff === 0;
}

async function hmacSign(secret, message) {
  const key = await crypto.subtle.importKey(
    "raw",
    new TextEncoder().encode(secret),
    { name: "HMAC", hash: HASH_ALGO },
    false,
    ["sign"],
  );
  return crypto.subtle.sign("HMAC", key, new TextEncoder().encode(message));
}

async function signJWT(payload, secret, ttl = JWT_TTL_SECONDS) {
  const header = { alg: "HS256", typ: "JWT" };
  const now = Math.floor(Date.now() / 1000);
  const body = { ...payload, iat: now, exp: now + ttl };
  const enc = new TextEncoder();
  const p1 = b64UrlEncode(enc.encode(JSON.stringify(header)));
  const p2 = b64UrlEncode(enc.encode(JSON.stringify(body)));
  const sig = await hmacSign(secret, `${p1}.${p2}`);
  return `${p1}.${p2}.${b64UrlEncode(sig)}`;
}

async function verifyJWT(token, secret) {
  if (!token) return null;
  const parts = token.split(".");
  if (parts.length !== 3) return null;
  const [p1, p2, sig] = parts;
  const expected = b64UrlEncode(await hmacSign(secret, `${p1}.${p2}`));
  // Constant-time-ish compare via length + character mismatch sum
  if (expected.length !== sig.length) return null;
  let diff = 0;
  for (let i = 0; i < expected.length; i++) {
    diff |= expected.charCodeAt(i) ^ sig.charCodeAt(i);
  }
  if (diff !== 0) return null;
  let payload;
  try {
    payload = JSON.parse(new TextDecoder().decode(b64UrlDecode(p2)));
  } catch {
    return null;
  }
  if (payload.exp && payload.exp < Math.floor(Date.now() / 1000)) return null;
  return payload;
}

// ----- github.js -----
// GitHub API client: read file via contents API, commit multi-file atomically via Git Data API.

const API = "https://api.github.com";

function cfg(env) {
  return {
    repo: env.GITHUB_REPO,
    branch: env.GITHUB_BRANCH || "main",
    token: env.GITHUB_TOKEN,
  };
}

async function gh(env, path, init = {}) {
  const { token } = cfg(env);
  const r = await fetch(`${API}${path}`, {
    ...init,
    headers: {
      Authorization: `Bearer ${token}`,
      Accept: "application/vnd.github+json",
      "User-Agent": "rexpand-admin-worker",
      "X-GitHub-Api-Version": "2022-11-28",
      ...(init.headers || {}),
    },
  });
  if (!r.ok) {
    const body = await r.text();
    throw new Error(
      `GitHub ${init.method || "GET"} ${path}: ${r.status} ${body.slice(0, 400)}`,
    );
  }
  // 204 No Content (refs PATCH on success may still return 200 with json; keep safe)
  if (r.status === 204) return null;
  return r.json();
}

function utf8ToB64(str) {
  // Workers don't have Buffer; encode bytes manually.
  const bytes = new TextEncoder().encode(str);
  let bin = "";
  for (let i = 0; i < bytes.length; i++) bin += String.fromCharCode(bytes[i]);
  return btoa(bin);
}

/**
 * Read file at HEAD of configured branch. Returns full UTF-8 text.
 *
 * Uses `Accept: application/vnd.github.raw` so we get the file body directly
 * instead of GitHub's JSON wrapper. The JSON wrapper truncates content to
 * empty string for files >1MB (index.html is 1.55MB), which would make every
 * marker lookup fail — see GitHub Contents API docs.
 */
async function readFile(env, path) {
  const { repo, branch, token } = cfg(env);
  const r = await fetch(
    `${API}/repos/${repo}/contents/${encodeURIComponent(path)}?ref=${branch}`,
    {
      headers: {
        Authorization: `Bearer ${token}`,
        Accept: "application/vnd.github.raw",
        "User-Agent": "rexpand-admin-worker",
        "X-GitHub-Api-Version": "2022-11-28",
      },
    },
  );
  if (!r.ok) {
    const body = await r.text();
    throw new Error(`GitHub read ${path}: ${r.status} ${body.slice(0, 400)}`);
  }
  return r.text();
}

/**
 * Commit multiple files atomically via the Git Data API.
 * files: [{ path: string, content: string }, ...]
 * Returns commit SHA.
 */
async function commitFiles(env, files, message) {
  const { repo, branch } = cfg(env);

  // 1. Latest ref → commit → tree
  const ref = await gh(env, `/repos/${repo}/git/ref/heads/${branch}`);
  const parentSha = ref.object.sha;
  const parentCommit = await gh(env, `/repos/${repo}/git/commits/${parentSha}`);
  const baseTreeSha = parentCommit.tree.sha;

  // 2. Create blobs
  const treeEntries = await Promise.all(
    files.map(async (f) => {
      const blob = await gh(env, `/repos/${repo}/git/blobs`, {
        method: "POST",
        body: JSON.stringify({
          content: utf8ToB64(f.content),
          encoding: "base64",
        }),
      });
      return { path: f.path, mode: "100644", type: "blob", sha: blob.sha };
    }),
  );

  // 3. New tree on top of base
  const tree = await gh(env, `/repos/${repo}/git/trees`, {
    method: "POST",
    body: JSON.stringify({ base_tree: baseTreeSha, tree: treeEntries }),
  });

  // 4. New commit
  const commit = await gh(env, `/repos/${repo}/git/commits`, {
    method: "POST",
    body: JSON.stringify({
      message,
      tree: tree.sha,
      parents: [parentSha],
    }),
  });

  // 5. Fast-forward branch
  await gh(env, `/repos/${repo}/git/refs/heads/${branch}`, {
    method: "PATCH",
    body: JSON.stringify({ sha: commit.sha, force: false }),
  });

  return commit.sha;
}

// ----- sync-html.js -----
// Regenerate sections of index.html from JSON data.
//
// Strategy: each replaceable region in index.html is wrapped in marker comments
// added once during Phase 1 setup (see scripts/add_html_markers.py).
//
//   HTML body markers (inside <body>):     <!-- @data:NAME:start --> ... <!-- @data:NAME:end -->
//   <script> markers (inside <script>):    // @data:NAME:start ... // @data:NAME:end
//
// The Worker NEVER touches HTML outside markers, so any other edits to
// index.html stay intact.

const HTML_START = (n) => `<!-- @data:${n}:start -->`;
const HTML_END = (n) => `<!-- @data:${n}:end -->`;
const JS_START = (n) => `// @data:${n}:start`;
const JS_END = (n) => `// @data:${n}:end`;

function replaceBetween(html, startMarker, endMarker, newBody) {
  const si = html.indexOf(startMarker);
  if (si < 0) throw new Error(`marker not found: ${startMarker}`);
  const ei = html.indexOf(endMarker, si + startMarker.length);
  if (ei < 0) throw new Error(`closing marker not found: ${endMarker}`);
  return (
    html.slice(0, si + startMarker.length) +
    "\n" +
    newBody +
    "\n" +
    html.slice(ei).replace(/^[ \t]*/, "")  // dedent the end marker we kept
  );
}

// --- HTML helpers ---

function esc(s) {
  return String(s ?? "")
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;")
    .replace(/"/g, "&quot;");
}

// ============================================================
// 1) Cases
// ============================================================

// Mirror of original `<div class="case-card">` structure (see index.html ~17690).
function renderCaseCard(c) {
  const dirShort = (c.dir || "").split(" / ")[0];
  const quoteHtml =
    c.has_narrative && c.quote
      ? `<div class="cc-quote">${esc(c.quote)}</div>`
      : `<div class="cc-quote cc-quote-soft">档案 <span class="cc-archive-id">#${esc(c.display_id)}</span> · Offer letter 留档 · 完整辅导记录可在 1v1 咨询中分享。</div>`;
  return `      <div class="case-card" data-dir="${esc(c.dir_key)}" data-case="${esc(c.id)}">
        <div class="cc-head">
          <span class="cc-tag"><span class="dot"></span>${esc(c.dir)}</span>
        </div>
        <div class="cc-student">
          <div class="cc-avatar">${esc(c.avatar)}</div>
          <div>
            <div class="cc-name">${esc(c.name_label)}</div>
            <div class="cc-school">${esc(c.school)} · <em>${esc(c.major)}</em></div>
          </div>
        </div>
        <div class="cc-offer">
          <div class="cc-arrow">→</div>
          <div class="cc-offer-body">
            <div class="cc-company">${esc(c.company)}</div>
            <div class="cc-role">${esc(c.role)}</div>
          </div>
        </div>
        <div class="cc-metrics">
          <div class="cc-metric"><div class="lbl">方向</div><div class="val">${esc(dirShort)}</div></div>
          <div class="cc-metric"><div class="lbl">学位</div><div class="val">${esc(c.degree)}</div></div>
        </div>
        ${quoteHtml}
        <div class="cc-foot">
          <span class="more" data-case-open="${esc(c.id)}">VIEW FULL CASE</span>
        </div>
      </div>`;
}

function syncCases(html, cases) {
  // 1. CASES_DATA single-line dict inside <script>
  const dataMap = {};
  for (const c of cases) {
    const { id, name_label, quote, ...rest } = c;
    dataMap[id] = rest;
  }
  let out = replaceBetween(
    html,
    JS_START("cases-data"),
    JS_END("cases-data"),
    `  const CASES_DATA = ${JSON.stringify(dataMap)};`,
  );

  // 2. case-card list in HTML
  const cardsHtml = cases.map(renderCaseCard).join("\n");
  out = replaceBetween(
    out,
    HTML_START("cases-cards"),
    HTML_END("cases-cards"),
    cardsHtml,
  );
  return out;
}

// ============================================================
// 2) Mentors
// ============================================================

function renderMentorCard(m) {
  const klass = m.has_video ? "mentor-card has-video" : "mentor-card";
  const dataVideo = m.has_video && m.video_url
    ? ` data-video="${esc(m.video_url)}"`
    : "";
  const avatarInner = m.has_video
    ? `<img src="${esc(m.avatar_src)}" alt="${esc(m.name)}"><div class="avatar-play">▶</div>`
    : `<img src="${esc(m.avatar_src)}" alt="${esc(m.name)}">`;
  const subBr = m.company_sub ? `<br>${esc(m.company_sub)}` : "";
  const liItems = (m.focus || []).map((t) => `<li>${esc(t)}</li>`).join("");
  return `      <div class="${klass}"${dataVideo}>
        <div class="avatar">${avatarInner}</div>
        <div class="name">${esc(m.name)}<span class="role">/ ${esc(m.role_title)}</span></div>
        <div class="company">${esc(m.company)}${subBr}</div>
        <div class="focus-label">— Focus</div>
        <ul class="focus-list">${liItems}</ul>
      </div>`;
}

function syncMentors(html, mentors) {
  const cards = mentors.map(renderMentorCard).join("\n");
  return replaceBetween(
    html,
    HTML_START("mentor-cards"),
    HTML_END("mentor-cards"),
    cards,
  );
}

// ============================================================
// 3) Replays (JSON-shaped → JS array literal via JSON.stringify)
// ============================================================

function syncReplays(html, replays) {
  const literal = `  const REPLAYS = ${JSON.stringify(replays, null, 2)};`;
  return replaceBetween(
    html,
    JS_START("replays"),
    JS_END("replays"),
    literal,
  );
}

// ============================================================
// 4) Articles (use mkImg(type, alt) helper for image field)
// ============================================================
//
// `image` shape in JSON: {type, alt}. Runtime expects {url, alt, credit} from
// mkImg(). To bridge, the index.html has a one-time post-process loop added
// in setup that calls mkImg(a.image.type, a.image.alt) when only {type,alt}
// is present. So plain JSON.stringify here is safe.

function syncArticles(html, articles) {
  const literal = `  const ARTICLES = ${JSON.stringify(articles, null, 2)};`;
  return replaceBetween(
    html,
    JS_START("articles"),
    JS_END("articles"),
    literal,
  );
}

// ============================================================
// Helper for the Worker: full multi-file commit content
// ============================================================

function buildCommitFiles(originalHtml, original, updates) {
  // updates: { cases?, mentors?, replays?, articles? }
  const files = [];
  let html = originalHtml;
  if (updates.cases) {
    html = syncCases(html, updates.cases);
    files.push({
      path: "data/cases.json",
      content: JSON.stringify(updates.cases, null, 2) + "\n",
    });
  }
  if (updates.mentors) {
    html = syncMentors(html, updates.mentors);
    files.push({
      path: "data/mentors.json",
      content: JSON.stringify(updates.mentors, null, 2) + "\n",
    });
  }
  if (updates.replays) {
    html = syncReplays(html, updates.replays);
    files.push({
      path: "data/replays.json",
      content: JSON.stringify(updates.replays, null, 2) + "\n",
    });
  }
  if (updates.articles) {
    html = syncArticles(html, updates.articles);
    files.push({
      path: "data/articles.json",
      content: JSON.stringify(updates.articles, null, 2) + "\n",
    });
  }
  if (html !== originalHtml) {
    files.push({ path: "index.html", content: html });
  }
  return files;
}

// ----- oss.js -----
// Aliyun OSS v4 signed PUT URL — returned to the browser so video upload
// goes direct-to-OSS, bypassing the Worker's body size limit.
//
// Spec: https://help.aliyun.com/zh/oss/developer-reference/include-signatures-in-the-url

async function hmacSha256Bytes(keyBytes, msg) {
  const key = await crypto.subtle.importKey(
    "raw", keyBytes, { name: "HMAC", hash: "SHA-256" }, false, ["sign"],
  );
  return new Uint8Array(
    await crypto.subtle.sign("HMAC", key, new TextEncoder().encode(msg)),
  );
}

function hex(bytes) {
  return Array.from(bytes).map((b) => b.toString(16).padStart(2, "0")).join("");
}

async function sha256Hex(s) {
  const buf = await crypto.subtle.digest("SHA-256", new TextEncoder().encode(s));
  return hex(new Uint8Array(buf));
}

function uriEncode(s, encodeSlash = true) {
  // RFC 3986 unreserved chars only; OSS v4 follows AWS sigv4 conventions.
  let out = "";
  for (const ch of s) {
    if (/[A-Za-z0-9\-._~]/.test(ch) || (!encodeSlash && ch === "/")) {
      out += ch;
    } else {
      const bytes = new TextEncoder().encode(ch);
      for (const b of bytes) {
        out += "%" + b.toString(16).toUpperCase().padStart(2, "0");
      }
    }
  }
  return out;
}

function isoStamp(date) {
  // YYYYMMDDTHHmmssZ (basic format)
  const pad = (n) => String(n).padStart(2, "0");
  return (
    date.getUTCFullYear() +
    pad(date.getUTCMonth() + 1) +
    pad(date.getUTCDate()) +
    "T" +
    pad(date.getUTCHours()) +
    pad(date.getUTCMinutes()) +
    pad(date.getUTCSeconds()) +
    "Z"
  );
}

/**
 * Build a signed URL the browser can PUT directly to OSS.
 *
 * @param env  Worker env with OSS_REGION, OSS_BUCKET, OSS_ENDPOINT,
 *             OSS_ACCESS_KEY_ID, OSS_ACCESS_KEY_SECRET
 * @param key  Object key (e.g. "videos/mentors/2026-05-31-jane.mp4")
 * @param contentType  MIME, e.g. "video/mp4"
 * @param ttl  URL validity in seconds (default 900 = 15min)
 */
async function presignPutObject(env, key, contentType, ttl = 900) {
  const ak = env.OSS_ACCESS_KEY_ID;
  const sk = env.OSS_ACCESS_KEY_SECRET;
  const region = env.OSS_REGION;
  const bucket = env.OSS_BUCKET;
  // Virtual-hosted style: https://<bucket>.<endpoint-host>
  const endpointUrl = new URL(env.OSS_ENDPOINT);
  const host = `${bucket}.${endpointUrl.host}`;

  const now = new Date();
  const amzDate = isoStamp(now);
  const dateStamp = amzDate.slice(0, 8);
  const credentialScope = `${dateStamp}/${region}/oss/aliyun_v4_request`;

  const queryParams = {
    "x-oss-signature-version": "OSS4-HMAC-SHA256",
    "x-oss-credential": `${ak}/${credentialScope}`,
    "x-oss-date": amzDate,
    "x-oss-expires": String(ttl),
    "x-oss-signed-headers": "host",
  };

  // Canonical query string (sorted, URI-encoded keys+values)
  const sortedKeys = Object.keys(queryParams).sort();
  const canonicalQuery = sortedKeys
    .map((k) => `${uriEncode(k)}=${uriEncode(queryParams[k])}`)
    .join("&");

  const canonicalUri = "/" + uriEncode(key, false);
  const canonicalHeaders = `host:${host}\n`;
  const signedHeaders = "host";
  const payloadHash = "UNSIGNED-PAYLOAD";

  const canonicalRequest = [
    "PUT",
    canonicalUri,
    canonicalQuery,
    canonicalHeaders,
    signedHeaders,
    payloadHash,
  ].join("\n");

  const stringToSign = [
    "OSS4-HMAC-SHA256",
    amzDate,
    credentialScope,
    await sha256Hex(canonicalRequest),
  ].join("\n");

  // Derive signing key: HMAC chain
  const enc = new TextEncoder();
  const k1 = await hmacSha256Bytes(enc.encode("aliyun_v4" + sk), dateStamp);
  const k2 = await hmacSha256Bytes(k1, region);
  const k3 = await hmacSha256Bytes(k2, "oss");
  const signingKey = await hmacSha256Bytes(k3, "aliyun_v4_request");
  const signature = hex(await hmacSha256Bytes(signingKey, stringToSign));

  const signedQuery = canonicalQuery + `&x-oss-signature=${uriEncode(signature)}`;
  const url = `https://${host}${canonicalUri}?${signedQuery}`;
  const publicUrl = `${env.OSS_PUBLIC_BASE}/${key}`;
  return { url, publicUrl, key, expiresIn: ttl };
}

const VIDEO_EXTS = new Set(["mp4", "mov", "webm", "m4v"]);

/** Sanitize + namespace an upload filename. */
function makeVideoKey(prefix, filename) {
  const safe = filename
    .toLowerCase()
    .replace(/[^a-z0-9._-]+/g, "-")
    .replace(/^-+|-+$/g, "");
  const ext = safe.split(".").pop() || "mp4";
  if (!VIDEO_EXTS.has(ext)) {
    throw new Error(`unsupported video extension: .${ext}`);
  }
  const stamp = new Date().toISOString().slice(0, 10);
  return `${prefix}/${stamp}-${safe}`;
}

// ----- puebulo.js -----
// Puebulo share-link importer.
//
// API: GET https://puebulo.com/api/share/<token>   (public, no auth)
// Response shape (verified 2026-05-31, see worker README for schema):
//   { session: {id, title, startedAt, durationSeconds, score, speakerRoles},
//     recordings: {videoUrl, audioUrl},
//     questions:  [{id, text, askedAtSeconds, kind: 'interviewer'|'candidate', ...}],
//     comments:   [...], utterances: [...] }
//
// We transform it into the REPLAYS schema used on /resources. Pueblo gives
// us only date / duration / video / questions automatically; the rest
// (company, role, score copy, summary, mainIssue, alsoNoting, tags) is
// human-curated in the admin form.

function fmtDuration(seconds) {
  if (!seconds || seconds <= 0) return "0:00";
  const total = Math.round(seconds);
  const h = Math.floor(total / 3600);
  const m = Math.floor((total % 3600) / 60);
  const s = total % 60;
  const pad = (n) => String(n).padStart(2, "0");
  return h > 0 ? `${h}:${pad(m)}:${pad(s)}` : `${m}:${pad(s)}`;
}

function fmtDate(iso) {
  if (!iso) return "";
  const d = new Date(iso);
  if (isNaN(d.getTime())) return "";
  return (
    d.getFullYear() +
    "." +
    String(d.getMonth() + 1).padStart(2, "0") +
    "." +
    String(d.getDate()).padStart(2, "0")
  );
}

function slugify(s) {
  return String(s)
    .toLowerCase()
    .replace(/[^\w\s.-]+/g, "")
    .replace(/[\s_]+/g, "-")
    .replace(/^-+|-+$/g, "")
    .slice(0, 80);
}

// Parse out a share token from either a raw token, a /share/<t> URL,
// or a full puebulo.com URL.
function parseToken(input) {
  if (!input) throw new Error("missing input");
  const s = String(input).trim();
  const m = s.match(/share\/([A-Za-z0-9_-]+)/);
  if (m) return m[1];
  if (/^[A-Za-z0-9_-]+$/.test(s)) return s;
  throw new Error(`could not parse Puebulo token from ${JSON.stringify(s)}`);
}

/**
 * Fetch a Puebulo share + transform to a partial REPLAY draft.
 * Returns { draft, raw }. The admin fills out the rest of the REPLAY before saving.
 */
async function importShare(input) {
  const token = parseToken(input);
  const r = await fetch(
    `https://puebulo.com/api/share/${encodeURIComponent(token)}`,
    { headers: { Accept: "application/json" }, cf: { cacheTtl: 0 } },
  );
  if (r.status === 404) throw new Error("Puebulo: share not found (404)");
  if (r.status === 410) throw new Error("Puebulo: share revoked (410)");
  if (!r.ok) {
    const body = await r.text();
    throw new Error(`Puebulo: ${r.status} ${body.slice(0, 200)}`);
  }
  const raw = await r.json();
  const session = raw.session || {};
  const recordings = raw.recordings || {};
  const questions = Array.isArray(raw.questions) ? raw.questions : [];

  // Map questions: keep only interviewer-asked (Pueblo's 'interviewer' kind);
  // candidate's clarifying questions are usually noise for our display.
  const interviewerQs = questions.filter((q) => q.kind !== "candidate");

  const dateStr = fmtDate(session.startedAt);
  // Slug: keep humans free to override; we provide a date-based default.
  const slugSeed = session.title || token;
  const slug = `${slugify(slugSeed)}-${dateStr.replace(/\./g, "-")}`;

  const draft = {
    slug,
    date: dateStr,
    duration: fmtDuration(session.durationSeconds),

    // === Filled by user in admin ===
    company: "",
    location: "",
    role: session.title || "",
    logo: "",
    seoTitle: "",
    dek: "",
    tags: [],

    // === Auto-filled from Pueblo ===
    videoSrc: recordings.videoUrl || "",
    questions: interviewerQs.map((q) => ({
      t: Math.round(q.askedAtSeconds || 0),
      q: (q.text || "").trim(),
      meta: "",
    })),

    // === Score: Pueblo's shape varies. We hand it through raw so admin can
    //     copy fields into our format; final REPLAY.score is built in UI. ===
    score: null,

    // === Free-form narrative; admin must write ===
    summary: "",
    mainIssue: "",
    alsoNoting: "",
  };

  return { draft, raw, pueblo_score_preview: session.score || null };
}

// ----- index.js -----
// Cloudflare Worker entry — backs webadmin.rexpandcareer.com.
//
// Routes (all under /api/):
//   POST   /api/login              { password } → { token }
//   GET    /api/state              → { cases, mentors, replays, articles, sha }
//   POST   /api/save               { cases?, mentors?, replays?, articles?, message? } → { commit }
//   POST   /api/upload-url         { prefix, filename, contentType } → { url, publicUrl }
//   POST   /api/puebulo            { input } → { draft, pueblo_score_preview }
//
// Everything except /api/login requires `Authorization: Bearer <jwt>`.





// --- response helpers ---
function jsonResponse(env, body, status = 200) {
  return new Response(JSON.stringify(body), {
    status,
    headers: {
      "Content-Type": "application/json; charset=utf-8",
      "Access-Control-Allow-Origin": env.ADMIN_ORIGIN || "*",
      "Access-Control-Allow-Credentials": "true",
      "Vary": "Origin",
    },
  });
}
function err(env, status, msg) {
  return jsonResponse(env, { error: msg }, status);
}

function corsPreflight(env) {
  return new Response(null, {
    status: 204,
    headers: {
      "Access-Control-Allow-Origin": env.ADMIN_ORIGIN || "*",
      "Access-Control-Allow-Credentials": "true",
      "Access-Control-Allow-Methods": "GET, POST, OPTIONS",
      "Access-Control-Allow-Headers": "Content-Type, Authorization",
      "Access-Control-Max-Age": "86400",
      "Vary": "Origin",
    },
  });
}

async function requireAuth(env, req) {
  const auth = req.headers.get("Authorization") || "";
  const m = auth.match(/^Bearer\s+(.+)$/i);
  if (!m) return null;
  return verifyJWT(m[1], env.JWT_SECRET);
}

// --- handlers ---

async function handleLogin(env, req) {
  let body;
  try {
    body = await req.json();
  } catch {
    return err(env, 400, "invalid JSON");
  }
  const ok = await verifyPassword(body.password || "", env.ADMIN_PASSWORD_HASH);
  if (!ok) return err(env, 401, "wrong password");
  const token = await signJWT({ sub: "admin" }, env.JWT_SECRET);
  return jsonResponse(env, { token, expiresIn: 8 * 3600 });
}

async function handleState(env, req) {
  const claims = await requireAuth(env, req);
  if (!claims) return err(env, 401, "unauthorized");

  // Pull the 4 data JSON files (single-source-of-truth for admin).
  const [casesRaw, mentorsRaw, replaysRaw, articlesRaw] = await Promise.all([
    readFile(env, "data/cases.json"),
    readFile(env, "data/mentors.json"),
    readFile(env, "data/replays.json"),
    readFile(env, "data/articles.json"),
  ]);
  return jsonResponse(env, {
    cases: JSON.parse(casesRaw),
    mentors: JSON.parse(mentorsRaw),
    replays: JSON.parse(replaysRaw),
    articles: JSON.parse(articlesRaw),
  });
}

async function handleSave(env, req) {
  const claims = await requireAuth(env, req);
  if (!claims) return err(env, 401, "unauthorized");
  let body;
  try {
    body = await req.json();
  } catch {
    return err(env, 400, "invalid JSON");
  }
  const updates = {
    cases: Array.isArray(body.cases) ? body.cases : undefined,
    mentors: Array.isArray(body.mentors) ? body.mentors : undefined,
    replays: Array.isArray(body.replays) ? body.replays : undefined,
    articles: Array.isArray(body.articles) ? body.articles : undefined,
  };
  if (
    !updates.cases &&
    !updates.mentors &&
    !updates.replays &&
    !updates.articles
  ) {
    return err(env, 400, "nothing to save");
  }

  // Pull the current index.html so we can apply the marker-based rewrites.
  const html = await readFile(env, "index.html");
  let files;
  try {
    files = buildCommitFiles(html, {}, updates);
  } catch (e) {
    return err(env, 500, `sync-html failed: ${e.message}`);
  }
  if (files.length === 0) return jsonResponse(env, { commit: null, note: "no-op" });

  const changedTypes = Object.keys(updates).filter((k) => updates[k]);
  const message = body.message?.trim() ||
    `webadmin: 更新 ${changedTypes.join(" / ")} (${changedTypes.map((t) => updates[t].length).join("/")} 条)`;
  const sha = await commitFiles(env, files, message);
  return jsonResponse(env, { commit: sha, files: files.map((f) => f.path) });
}

async function handleUploadUrl(env, req) {
  const claims = await requireAuth(env, req);
  if (!claims) return err(env, 401, "unauthorized");
  const body = await req.json().catch(() => ({}));
  const prefix = body.prefix || "videos/misc";
  if (!/^videos\/(mentors|replays|misc)$/.test(prefix)) {
    return err(env, 400, "prefix must be videos/mentors, videos/replays, or videos/misc");
  }
  if (!body.filename) return err(env, 400, "filename required");
  if (!body.contentType) return err(env, 400, "contentType required");
  let key;
  try {
    key = makeVideoKey(prefix, body.filename);
  } catch (e) {
    return err(env, 400, e.message);
  }
  const presigned = await presignPutObject(env, key, body.contentType);
  return jsonResponse(env, presigned);
}

async function handlePuebulo(env, req) {
  const claims = await requireAuth(env, req);
  if (!claims) return err(env, 401, "unauthorized");
  const body = await req.json().catch(() => ({}));
  if (!body.input) return err(env, 400, "input required (token or share URL)");
  try {
    const result = await importShare(body.input);
    return jsonResponse(env, result);
  } catch (e) {
    return err(env, 502, e.message);
  }
}

// --- router ---
export default {
  async fetch(req, env) {
    if (req.method === "OPTIONS") return corsPreflight(env);
    const url = new URL(req.url);

    if (!url.pathname.startsWith("/api/")) {
      return err(env, 404, "not found");
    }
    try {
      switch (`${req.method} ${url.pathname}`) {
        case "POST /api/login":
          return await handleLogin(env, req);
        case "GET /api/state":
          return await handleState(env, req);
        case "POST /api/save":
          return await handleSave(env, req);
        case "POST /api/upload-url":
          return await handleUploadUrl(env, req);
        case "POST /api/puebulo":
          return await handlePuebulo(env, req);
        case "GET /api/health":
          return jsonResponse(env, { ok: true, time: new Date().toISOString() });
      }
      return err(env, 404, "no such route");
    } catch (e) {
      return err(env, 500, `worker error: ${e.message}`);
    }
  },
};
